# @cctt_verify {"v":2,"sym":"sympy.ntheory.egyptian_fraction.egypt_takenouchi","kind":"function","src_hash":"28488fbd19f1ed08","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"egypt_takenouchi(x, y)","rhs":"<unspecified:egypt_takenouchi>","over":{"base":"Any"},"name":"egypt_takenouchi_correct"},"guarantee":"egypt_takenouchi produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.ntheory.egyptian_fraction.egypt_takenouchi_correct","statement":"Path(egypt_takenouchi(x), egypt_takenouchi produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"0b1a1407f9f6e0b6","spec_source":"static","formal_spec":{"source":"static","strength":"trivial","pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.3,"verdict_class":"assumed","binding":true}}
def egypt_takenouchi(x, y):
    # assumes gcd(x, y) == 1
    # special cases for 3/y
    if x == 3:
        if y % 2 == 0:
            return [y//2, y]
        i = (y - 1)//2
        j = i + 1
        k = j + i
        return [j, k, j*k]
    l = [y] * x
    while len(l) != len(set(l)):
        l.sort()
        for i in range(len(l) - 1):
            if l[i] == l[i + 1]:
                break
        k = l[i]
        if k % 2 == 0:
            l[i] = l[i] // 2
            del l[i + 1]
        else:
            l[i], l[i + 1] = (k + 1)//2, k*(k + 1)//2
    return sorted(l)


